  ('disabled-e0adf6cd-moex-00008', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依據憲法本文之規定，監察院提出糾正案之對象為何？', '["行政院及其有關部會", "立法院", "司法院", "考試院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00009', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依憲法法庭判決，關於誹謗罪與言論自由之保障，下列敘述何者錯誤？', '["人民之名譽權與言論自由，應受憲法無分軒輊之保障，國家原則上均應 給予最大限度之保障", "表意人未提供佐證依據之事實性言論，縱內容涉及公共事務，對公益論 辯貢獻度仍不高，該言論所指述者之名譽權應受較高程度之保障", "涉及私德之誹謗言論，與公共利益無關時，表意人之言論自由應完全退 讓於被指述者名譽權與隱私權之保護", "表意人於社群媒體與自媒體上所為誹謗言論，與一般人日常生活中以言 詞所為口耳間傳播之誹謗言論，在事前查證程序之要求上，並無不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00010', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '有關憲法保障之隱私權，下列敘述何者錯誤？', '["隱私權保障範圍包括個人生活私密領域免於他人侵擾之權利", "基於人性尊嚴與個人主體性之維護及人格發展之完整，隱私權為不可或 缺之基本權利", "隱私權保障範圍包括個人資料之自主控制權利", "就資訊隱私權而言，保障人民決定是否揭露其個人資料，但不包括對其 個人資料記載錯誤之更正權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00011', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依司法院大法官解釋，下列那一基本權利非以憲法第22條規定為依據？', '["資訊隱私權", "原住民（族）身分認同權", "人民收養子女之自由", "通訊傳播自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00012', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依司法院釋字第 756 號，有關監獄管理機關對受刑人秘密通訊自由之限 制，下列敘述何者錯誤？', '["監獄長官以儀器檢查書信之內容物，不必然影響通訊內容之秘密性", "監獄長官不區分書信種類，一律閱讀受刑人之書信，係屬違憲侵害其秘 密通訊自由之行為", "監獄長官以維護監獄紀律（例如監所之名譽）為由，要求受刑人刪除書 信之內容，非屬限制其秘密通訊自由之正當目的", "受刑人書信之內容遭刪除者，應保留書信全文影本，嗣受刑人出獄時發 還之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00013', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋，關於行政院院長，下列敘述何者 錯誤？', '["總統發布行政院院長的免職令，無須行政院院長副署", "有關行政院院長的任期，並無明文規定", "立法院對行政院院長所提出的不信任案如未獲通過，不得對同一行政院 院長再提不信任案", "總統藉由其任命的行政院院長，變更先前存在，與其政見未洽之施政方 針或政策，屬政黨政治常態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00014', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '憲法第 73 條規定，立法委員在院內所為之言論及表決，對院外不負責 任。依司法院釋字第435號，關於立法委員之言論免責權，下列敘述何者 錯誤？', '["司法機關為維護社會秩序及被害人權益，對於立法委員行為是否逾越免 責保障之範圍，於必要時得依法行使偵審之權限", "舉凡在院會或委員會之發言、質詢、提案、表決以及與此直接相關之附 隨行為，均屬應予保障之事項", "與行使職權無關之行為，諸如蓄意之肢體動作等，顯然不符意見表達之 適當情節致侵害他人法益者，不在保障之列", "言論免責權為憲法賦予立法委員之例外特權，故其保障範圍應作最小程 度之嚴格界定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00015', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '下列何者之自治權，受憲法保障？', '["鄉（鎮、市）", "獨立行政機關", "大學", "祭祀公業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00016', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '下列何項敘述，符合司法院大法官就「法律明確性原則」所闡釋之內容？', '["法律明確性之要求，指法律文義須具體詳盡", "立法者於制定法律時，不得運用不確定法律概念", "法律規定是否明確，得自法條文義、立法目的與法體系整體關聯性觀察 得知", "是否違反法律明確性原則與法規範之意義得否由司法審查加以確認一 事無關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00017', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '有關「行政裁量」與「不確定法律概念」之區別，下列敘述何者正確？', '["不確定法律概念僅存在於公法法規", "在行政裁量範圍內的各項選擇原則上僅生適當與否的問題", "行政機關就不確定法律概念享有判斷餘地時，行政法院以介入審查為 原則", "就行政機關之裁量，行政法院得為妥當性之審查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL)
